SELECT category_name, COUNT(article_id) AS article_count
FROM article_categories
GROUP BY category_name;

SELECT COUNT(article_id) AS article_count
FROM article_categories
WHERE category_name = 'category2';

SELECT a.title, a.content, a.created_at
FROM articles a
INNER JOIN article_popular p ON a.article_id = p.article_id;

SELECT T1.title
FROM articles AS T1
INNER JOIN article_featured AS T2 ON T1.article_id = T2.article_id;

SELECT COUNT(*) AS report_count
FROM comment_reports
WHERE report_status = 'pending';
